SourceCode.Declaration:
/// <summary>
/// Contract class for the process "Import warehouse outputs" of transfer journals,
/// for the ETGSPAIN model.
/// </summary>
[DataContract,
 SysOperationContractProcessing(classStr(ETGSPAINInventJournalLineImportUIBuilder))]
class ETGSPAINInventJournalLineImportContract implements SysOperationValidatable
{
    InventJournalId     inventJournalId;
    InventLocationId    inventLocationId;
    System.IO.Stream    inputDataStream;

}

Method.Source:
/// <summary>
/// Transfer journal number parameter.
/// </summary>
/// <param name = "_inventJournalId">Journal number</param>
/// <returns>Journal number.</returns>
[DataMember]
public InventJournalId parmInventJournalId(InventJournalId _inventJournalId = inventJournalId)
{
    inventJournalId = _inventJournalId;
    return inventJournalId;
}

/// <summary>
/// Output warehouse parameter.
/// </summary>
/// <param name = "_inventLocationId">Warehouse</param>
/// <returns>Warehouse</returns>
[DataMember]
public InventLocationId parmInventLocationId(InventLocationId _inventLocationId = inventLocationId)
{
    inventLocationId = _inventLocationId;
    return inventLocationId;
}

/// <summary>
/// File upload parameter.
/// </summary>
/// <param name = "_value">File to upload</param>
/// <returns>File to upload</returns>
public System.IO.Stream parmInputDataStream(System.IO.Stream _value = inputDataStream)
{
    inputDataStream = _value;
    return inputDataStream;
}

/// <summary>
/// Determines if the parameters are valid.
/// </summary>
/// <returns>
/// True if the parameters are valid; otherwise, False.
/// </returns>
public boolean validate()
{
    boolean isValid = true;

    if (!inventJournalId)
    {
        isValid = checkFailed(strFmt("@ETGSPAINLabels:NoSelected", "@ETGSPAINLabels:InventJournalNum"));
    }

    if (!inventLocationId)
    {
        isValid = checkFailed(strFmt("@ETGSPAINLabels:NoSelected", "@ETGSPAINLabels:InventLocationOutput"));
    }

    if (!inputDataStream)
    {
        isValid = checkFailed(strFmt("@ETGSPAINLabels:NoSelected", "@ETGSPAINLabels:UploadFileData"));
    }

    return isValid;
}
